// Deepfake-/Manipulations-Check: kombiniert Sightengine-Modelle deepfake + genai zu einem Gesamtscore.
async function run(input) {
  const url = String((input && input.imageUrl) || '').trim();
  const apiUser = String((input && input.apiUser) || '').trim();
  const apiSecret = String((input && input.apiSecret) || '').trim();
  if (!/^https?:\/\//.test(url)) return { fehler: 'Bitte eine vollstaendige Bild-URL (http/https) angeben.' };
  if (!apiUser || !apiSecret) return { fehler: 'Sightengine api_user und api_secret noetig (Gratis-Tier auf sightengine.com).' };
  const ep = 'https://api.sightengine.com/1.0/check.json?models=deepfake,genai'
    + '&api_user=' + encodeURIComponent(apiUser)
    + '&api_secret=' + encodeURIComponent(apiSecret)
    + '&url=' + encodeURIComponent(url);
  let d;
  try {
    const res = await fetch(ep);
    if (!res.ok) return { fehler: 'Sightengine antwortete mit HTTP ' + res.status + ' — Schluessel oder Kontingent pruefen.' };
    d = await res.json();
  } catch (e) {
    return { fehler: 'Sightengine nicht erreichbar (Zeitueberschreitung oder Netzwerkfehler). Bitte spaeter erneut versuchen.' };
  }
  if (!d || d.status !== 'success') return { fehler: (d && d.error && d.error.message) || 'Pruefung fehlgeschlagen.' };
  const deepfake = (d.type && typeof d.type.deepfake === 'number') ? d.type.deepfake : 0;
  const aiGen = (d.type && typeof d.type.ai_generated === 'number') ? d.type.ai_generated : 0;
  const score = Math.max(deepfake, aiGen); // hoechstes Signal bestimmt die Bewertung
  function stufe(s) {
    if (s < 0.2) return 'sehr wahrscheinlich echt';
    if (s < 0.5) return 'unklar';
    if (s < 0.8) return 'wahrscheinlich manipuliert';
    return 'sehr wahrscheinlich manipuliert';
  }
  return {
    gesamtscore: Math.round(score * 1000) / 1000,
    prozent: Math.round(score * 100) + '%',
    bewertung: stufe(score),
    signale: {
      deepfakeGesicht: Math.round(deepfake * 100) + '%',
      kiGeneriert: Math.round(aiGen * 100) + '%'
    },
    begruendung: 'Kombiniert Deepfake-Erkennung (Gesichtstausch) und KI-Generierungs-Erkennung. Das hoechste Einzelsignal bestimmt die Stufe.',
    hinweis: 'Wahrscheinlichkeit, kein forensischer Beweis. Fuer hoehere Sicherheit mehrere Dienste kombinieren.',
    bild: url
  };
}
